   279→    private CloseableIterator<Record> compressedIterator(BufferSupplier bufferSupplier, boolean skipKeyValue) {
   280→        final InputStream inputStream = recordInputStream(bufferSupplier);
   281→
   282→        if (skipKeyValue) {
   283→            return new StreamRecordIterator(inputStream) {
   284→                @Override
   285→                protected Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException {
   286→                    return DefaultRecord.readPartiallyFrom(inputStream, baseOffset, baseTimestamp, baseSequence, logAppendTime);
   287→                }
   288→            };
   289→        } else {
   290→            return new StreamRecordIterator(inputStream) {
   291→                @Override
   292→                protected Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException {
   293→                    return DefaultRecord.readFrom(inputStream, baseOffset, baseTimestamp, baseSequence, logAppendTime);
   294→                }
   295→            };
   296→        }
   297→    }
