   320→    @Override
   321→    public Iterator<Record> iterator() {
   322→        if (count() == 0)
   323→            return Collections.emptyIterator();
   324→
   325→        if (!isCompressed())
   326→            return uncompressedIterator();
   327→
   328→        // for a normal iterator, we cannot ensure that the underlying compression stream is closed,
   329→        // so we decompress the full record set here. Use cases which call for a lower memory footprint
   330→        // can use `streamingIterator` at the cost of additional complexity
   331→        try (CloseableIterator<Record> iterator = compressedIterator(BufferSupplier.NO_CACHING, false)) {
   332→            List<Record> records = new ArrayList<>(count());
   333→            while (iterator.hasNext())
   334→                records.add(iterator.next());
   335→            return records.iterator();
   336→        }
   337→    }
