   339→    @Override
   340→    public CloseableIterator<Record> skipKeyValueIterator(BufferSupplier bufferSupplier) {
   341→        if (count() == 0) {
   342→            return CloseableIterator.wrap(Collections.emptyIterator());
   343→        }
   344→
   345→        /*
   346→         * For uncompressed iterator, it is actually not worth skipping key / value / headers at all since
   347→         * its ByteBufferInputStream's skip() function is less efficient compared with just reading it actually
   348→         * as it will allocate new byte array.
   349→         */
   350→        if (!isCompressed())
   351→            return uncompressedIterator();
   352→
   353→        // we define this to be a closable iterator so that caller (i.e. the log validator) needs to close it
   354→        // while we can save memory footprint of not decompressing the full record set ahead of time
   355→        return compressedIterator(bufferSupplier, true);
   356→    }
