   379→        buffer.putShort(ATTRIBUTES_OFFSET, attributes);
   380→        buffer.putLong(MAX_TIMESTAMP_OFFSET, maxTimestamp);
   381→        long crc = computeChecksum();
   382→        ByteUtils.writeUnsignedInt(buffer, CRC_OFFSET, crc);
