   442→    public static void writeEmptyHeader(ByteBuffer buffer,
   443→                                        byte magic,
   444→                                        long producerId,
   445→                                        short producerEpoch,
   446→                                        int baseSequence,
   447→                                        long baseOffset,
   448→                                        long lastOffset,
   449→                                        int partitionLeaderEpoch,
   450→                                        TimestampType timestampType,
   451→                                        long timestamp,
   452→                                        boolean isTransactional,
   453→                                        boolean isControlRecord) {
   454→        int offsetDelta = (int) (lastOffset - baseOffset);
   455→        writeHeader(buffer, baseOffset, offsetDelta, DefaultRecordBatch.RECORD_BATCH_OVERHEAD, magic,
   456→                    CompressionType.NONE, timestampType, RecordBatch.NO_TIMESTAMP, timestamp, producerId,
   457→                    producerEpoch, baseSequence, isTransactional, isControlRecord, false, partitionLeaderEpoch, 0);
   458→    }
