   511→    public static int sizeInBytes(long baseOffset, Iterable<Record> records) {
   512→        Iterator<Record> iterator = records.iterator();
   513→        if (!iterator.hasNext())
   514→            return 0;
   515→
   516→        int size = RECORD_BATCH_OVERHEAD;
   517→        Long baseTimestamp = null;
   518→        while (iterator.hasNext()) {
   519→            Record record = iterator.next();
   520→            int offsetDelta = (int) (record.offset() - baseOffset);
   521→            if (baseTimestamp == null)
   522→                baseTimestamp = record.timestamp();
   523→            long timestampDelta = record.timestamp() - baseTimestamp;
   524→            size += DefaultRecord.sizeInBytes(offsetDelta, timestampDelta, record.key(), record.value(),
   525→                    record.headers());
   526→        }
   527→        return size;
   528→    }
