   530→    public static int sizeInBytes(Iterable<SimpleRecord> records) {
   531→        Iterator<SimpleRecord> iterator = records.iterator();
   532→        if (!iterator.hasNext())
   533→            return 0;
   534→
   535→        int size = RECORD_BATCH_OVERHEAD;
   536→        int offsetDelta = 0;
   537→        Long baseTimestamp = null;
   538→        while (iterator.hasNext()) {
   539→            SimpleRecord record = iterator.next();
   540→            if (baseTimestamp == null)
   541→                baseTimestamp = record.timestamp();
   542→            long timestampDelta = record.timestamp() - baseTimestamp;
   543→            size += DefaultRecord.sizeInBytes(offsetDelta++, timestampDelta, record.key(), record.value(),
   544→                    record.headers());
   545→        }
   546→        return size;
   547→    }
