   595→
   596→        @Override
   597→        public Record next() {
   598→            if (readRecords >= numRecords)
   599→                throw new NoSuchElementException();
   600→
   601→            readRecords++;
   602→            Record rec = readNext(baseOffset, baseTimestamp, baseSequence, logAppendTime);
   603→            if (readRecords == numRecords) {
   604→                // Validate that the actual size of the batch is equal to declared size
   605→                // by checking that after reading declared number of items, there no items left
   606→                // (overflow case, i.e. reading past buffer end is checked elsewhere).
   607→                if (!ensureNoneRemaining())
   608→                    throw new InvalidRecordException("Incorrect declared batch size, records still remaining in file");
   609→            }
   610→            return rec;
   611→        }
