   431→        private void validateBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset) {
   432→            if (maxTimestamp != RecordBatch.NO_TIMESTAMP && shallowOffsetOfMaxTimestamp < 0)
   433→                throw new IllegalArgumentException("shallowOffset undefined for maximum timestamp " + maxTimestamp);
   434→            if (maxOffset < 0)
   435→                throw new IllegalArgumentException("maxOffset undefined");
   436→        }
