/**
 * Concrete implementation of {@link RecordBatch} for Kafka record format magic version 2 and above.
 *
 * <p><strong>Binary Layout:</strong>
 * This class handles the serialization/deserialization of the following binary schema:
 * <pre>
 * RecordBatch =>
 *  BaseOffset => Int64
 *  Length => Int32
 *  PartitionLeaderEpoch => Int32
 *  Magic => Int8
 *  CRC => Uint32
 *  Attributes => Int16
 *  LastOffsetDelta => Int32 // also serves as LastSequenceDelta
 *  BaseTimestamp => Int64
 *  MaxTimestamp => Int64
 *  ProducerId => Int64
 *  ProducerEpoch => Int16
 *  BaseSequence => Int32
 *  RecordsCount => Int32
 *  Records => [Record]
 * </pre>
 *
 * <p><strong>Compression:</strong>
 * When compression is enabled, the record data following the RecordsCount field is compressed as a single block.
 * Decompression is performed lazily when iterating over records via {@link #streamingIterator(BufferSupplier)}
 * or eagerly in {@link #iterator()} to avoid resource leaks.
 *
 * <p><strong>CRC Computation:</strong>
 * The CRC-32C (Castagnoli) polynomial covers all batch data from the Attributes field onwards (excluding
 * PartitionLeaderEpoch which is not included in CRC computation to avoid recomputation on broker assignment).
 *
 * <p><strong>Compaction & Producer State Preservation:</strong>
 * During log compaction, this batch preserves base and last offset/sequence numbers from the original batch,
 * allowing brokers to rebuild accurate producer state. Empty batches may be retained to preserve producer
 * sequence information until a new sequence is written or the producer ID expires.
 *
 * <p><strong>Timestamp Semantics:</strong>
 * BaseTimestamp represents the timestamp of the first record (or delete horizon for tombstone batches).
 * MaxTimestamp reflects the maximum timestamp of retained records (for CREATE_TIME) or the broker-assigned
 * log append time (for LOG_APPEND_TIME).
 *
 * <p><strong>Batch Attributes:</strong>
 * <table border="1">
 *   <tr><th>Bits</th><th>Field</th></tr>
 *   <tr><td>0-2</td><td>Compression Type (0=None, 1=GZIP, 2=Snappy, 3=LZ4, 4=Zstandard)</td></tr>
 *   <tr><td>3</td><td>Timestamp Type (0=CreateTime, 1=LogAppendTime)</td></tr>
 *   <tr><td>4</td><td>Transactional Flag</td></tr>
 *   <tr><td>5</td><td>Control Flag (control batches for transaction markers)</td></tr>
 *   <tr><td>6</td><td>Delete Horizon Flag</td></tr>
 *   <tr><td>7-15</td><td>Reserved</td></tr>
 * </table>
 *
 * <p><strong>Thread Safety:</strong>
 * This class is NOT thread-safe. The underlying ByteBuffer is accessed without synchronization.
 * Multiple threads must not read or write the same DefaultRecordBatch instance concurrently.
 * Thread-safe access requires external synchronization or per-thread instances.
 *
 * <p><strong>Performance Characteristics:</strong>
 * <ul>
 *   <li><strong>Lazy Decompression:</strong> Use {@link #streamingIterator(BufferSupplier)} to decompress
 *       records on-demand, reducing memory footprint for large compressed batches.</li>
 *   <li><strong>CRC Computation:</strong> {@link #isValid()} recomputes the CRC every time; cache results
 *       if validating the same batch multiple times.</li>
 *   <li><strong>Iterator Creation:</strong> {@link #iterator()} decompresses the entire batch immediately
 *       for regular iterator support, while {@link #streamingIterator(BufferSupplier)} defers decompression.</li>
 * </ul>
 *
 * @see RecordBatch for the interface contract
 * @see MemoryRecords for managing multiple batches in memory
 */
public class DefaultRecordBatch extends AbstractRecordBatch implements MutableRecordBatch {
    static final int BASE_OFFSET_OFFSET = 0;
    static final int BASE_OFFSET_LENGTH = 8;
    static final int LENGTH_OFFSET = BASE_OFFSET_OFFSET + BASE_OFFSET_LENGTH;
    static final int LENGTH_LENGTH = 4;
    static final int PARTITION_LEADER_EPOCH_OFFSET = LENGTH_OFFSET + LENGTH_LENGTH;
    static final int PARTITION_LEADER_EPOCH_LENGTH = 4;
    static final int MAGIC_OFFSET = PARTITION_LEADER_EPOCH_OFFSET + PARTITION_LEADER_EPOCH_LENGTH;
