     *
     * <p>This may be smaller than {@link #sizeInBytes()} if the buffer contains partial or incomplete
     * batches at the end (e.g., during network transmission or incomplete writes).
     * The result is cached after the first invocation; it does not reflect changes to the underlying
     * buffer.
     *
     * @return The number of valid bytes representing complete batches
     */
    public int validBytes() {
        if (validBytes >= 0)
            return validBytes;

        int bytes = 0;
        for (RecordBatch batch : batches())
            bytes += batch.sizeInBytes();

        this.validBytes = bytes;
        return bytes;
    }

    @Override
    public AbstractIterator<MutableRecordBatch> batchIterator() {
        return new RecordBatchIterator<>(new ByteBufferLogInputStream(buffer.duplicate(), Integer.MAX_VALUE));
    }

